import{_ as s,H as a,f as n,i as e}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"高可用三件套","description":"","frontmatter":{},"headers":[],"relativePath":"systemDesign/05-高可用三件套.md","filePath":"systemDesign/05-高可用三件套.md","lastUpdated":1778496697000}'),o={name:"systemDesign/05-高可用三件套.md"};function l(i,t,r,p,d,h){return a(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="高可用三件套" tabindex="-1">高可用三件套 <a class="header-anchor" href="#高可用三件套" aria-label="Permalink to &quot;高可用三件套&quot;">​</a></h1><p>「我们系统 99.99% 可用」是面试和 PR 稿里最爱出现的一句话,但<strong>几乎没人能解释清楚这个数字怎么来的</strong>。99.99% 听上去很高,<strong>实际意味着一年只允许累计挂 52 分钟</strong>——任何一个生产事故都可能一次性烧光一年的「故障预算」。这一篇讲清楚两件事:<strong>这个数字怎么算出来</strong>,以及<strong>怎样的工程努力才能真正达成</strong>——本质就是三个基础动作:冗余、故障转移、健康检查。</p><blockquote><p>一句话先记住:<strong>高可用不是堆设备,是一套&quot;假设单点必挂&quot;的工程纪律</strong>——任何节点都可能挂,所以任何节点都要有副本(冗余);挂了要能自动切走流量(故障转移);切走前提是必须知道它挂了(健康检查)。<strong>这三件事缺一个,可用性数字都是骗人的</strong>。</p></blockquote><hr><h2 id="一、可用性的数字感" tabindex="-1">一、可用性的数字感 <a class="header-anchor" href="#一、可用性的数字感" aria-label="Permalink to &quot;一、可用性的数字感&quot;">​</a></h2><p>「9 的个数」是行业通用语言,<strong>必须背熟</strong>:</p><table tabindex="0"><thead><tr><th>可用性</th><th>一年允许停机</th><th>一月允许停机</th><th>一周允许停机</th><th>适合场景</th></tr></thead><tbody><tr><td>90%(1 个 9)</td><td>36.5 天</td><td>72 小时</td><td>16.8 小时</td><td>内部工具</td></tr><tr><td>99%(2 个 9)</td><td>3.65 天</td><td>7.2 小时</td><td>1.68 小时</td><td>普通后台</td></tr><tr><td>99.9%(3 个 9)</td><td>8.77 小时</td><td>43.8 分钟</td><td>10.1 分钟</td><td>中型业务</td></tr><tr><td>99.99%(4 个 9)</td><td>52.6 分钟</td><td>4.4 分钟</td><td>1.01 分钟</td><td>主流互联网</td></tr><tr><td>99.999%(5 个 9)</td><td>5.26 分钟</td><td>26 秒</td><td>6 秒</td><td>电信 / 银行</td></tr><tr><td>99.9999%(6 个 9)</td><td>31.5 秒</td><td>2.6 秒</td><td>0.6 秒</td><td>极致核心</td></tr></tbody></table><blockquote><p><strong>「我们要 5 个 9」 是一句很贵的话</strong>——一年只能挂 5 分钟,这要求秒级故障转移 + 多机房 + 全自动恢复。<strong>大多数业务做到 99.95% 已经很优秀了</strong>——别一上来吹 5 个 9。</p></blockquote><h3 id="_1-1-可用性的串联与并联" tabindex="-1">1.1 可用性的串联与并联 <a class="header-anchor" href="#_1-1-可用性的串联与并联" aria-label="Permalink to &quot;1.1 可用性的串联与并联&quot;">​</a></h3><p>系统由多个组件组成,可用性怎么算?</p><p><strong>串联</strong>(任一挂全挂):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 99.9% → B 99.9% → C 99.9% = 99.9% × 99.9% × 99.9% = 99.7%</span></span></code></pre></div><p><strong>并联</strong>(冗余,任一活就活):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 主 99.9% + A 备 99.9%(并联)= 1 - (0.1% × 0.1%) = 99.9999%</span></span></code></pre></div><blockquote><p><strong>冗余的威力</strong>:两个 99.9% 的副本并联得到 99.9999%——多一个副本,多 3 个 9。<strong>这就是高可用的基本武器</strong>。 <strong>串联的悲剧</strong>:链路上每多一个组件,可用性都打折扣。<strong>所以减少依赖比加副本更高级</strong>。</p></blockquote><h3 id="_1-2-可用性-vs-可靠性-vs-持久性" tabindex="-1">1.2 可用性 vs 可靠性 vs 持久性 <a class="header-anchor" href="#_1-2-可用性-vs-可靠性-vs-持久性" aria-label="Permalink to &quot;1.2 可用性 vs 可靠性 vs 持久性&quot;">​</a></h3><p>经常被混用,实际不同:</p><table tabindex="0"><thead><tr><th>术语</th><th>含义</th></tr></thead><tbody><tr><td>可用性(Availability)</td><td>用户请求时,系统能响应的概率</td></tr><tr><td>可靠性(Reliability)</td><td>系统在一段时间内不出故障的概率</td></tr><tr><td>持久性(Durability)</td><td>已写入的数据不丢失的概率(S3 的 11 个 9 就是这个)</td></tr></tbody></table><blockquote><p>别把「数据不丢」(持久性)和「服务能响应」(可用性)混了。<strong>S3 持久性 99.999999999%(11 个 9),可用性「只有」99.99%</strong>——意思是数据基本不会丢,但服务偶尔会超时。</p></blockquote><hr><h2 id="二、第一件套-冗余-redundancy" tabindex="-1">二、第一件套:冗余(Redundancy) <a class="header-anchor" href="#二、第一件套-冗余-redundancy" aria-label="Permalink to &quot;二、第一件套:冗余(Redundancy)&quot;">​</a></h2><p>冗余 = 「这个组件挂了我还有一个」。<strong>没有冗余的系统不是高可用系统,只是单机系统外面包了层壳</strong>。</p><h3 id="_2-1-冗余的几种粒度" tabindex="-1">2.1 冗余的几种粒度 <a class="header-anchor" href="#_2-1-冗余的几种粒度" aria-label="Permalink to &quot;2.1 冗余的几种粒度&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>进程冗余    一台机器多个进程(占用 CPU)</span></span>
<span class="line"><span>机器冗余    一个集群多台机器(应用层最常用)</span></span>
<span class="line"><span>机架冗余    跨机架部署(防一个机架供电故障)</span></span>
<span class="line"><span>机房冗余    跨可用区(AZ)部署(防机房整体故障)</span></span>
<span class="line"><span>地域冗余    跨地域部署(防地震、政策、海底光缆断)</span></span></code></pre></div><p><strong>经验值</strong>:</p><ul><li>互联网应用的标准是<strong>跨 AZ</strong>(同地域多机房)</li><li>金融 / 电商核心是<strong>跨地域</strong>(异地容灾)</li><li>全球业务(社交、电商)是<strong>全球分布</strong></li></ul><h3 id="_2-2-冗余的副本数-n-1-不够-n-2-才稳" tabindex="-1">2.2 冗余的副本数:N+1 不够,N+2 才稳 <a class="header-anchor" href="#_2-2-冗余的副本数-n-1-不够-n-2-才稳" aria-label="Permalink to &quot;2.2 冗余的副本数:N+1 不够,N+2 才稳&quot;">​</a></h3><p>业务峰值需要 N 台机器扛,<strong>冗余配多少</strong>?</p><ul><li><strong>N+1</strong>:能扛一台挂的故障,但<strong>滚动升级时另一台再挂就崩</strong></li><li><strong>N+2</strong>(推荐):允许同时一台挂 + 一台维护</li><li><strong>2N</strong>:多机房双活,任一机房全挂还能扛</li></ul><blockquote><p>新手最常见错误是<strong>按峰值刚好配机器</strong>,那叫「容量规划」,不是「高可用」。<strong>真正的高可用是峰值容量 × 2</strong>——剩下一半在等故障。</p></blockquote><h3 id="_2-3-冗余不只是机器-是整链路" tabindex="-1">2.3 冗余不只是机器,是整链路 <a class="header-anchor" href="#_2-3-冗余不只是机器-是整链路" aria-label="Permalink to &quot;2.3 冗余不只是机器,是整链路&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DNS 多解析记录 → 多个入口 IP</span></span>
<span class="line"><span>LB 多实例    → keepalived / VIP 漂移</span></span>
<span class="line"><span>Web 多副本   → 集群 + LB</span></span>
<span class="line"><span>DB 主从     → 自动主从切换</span></span>
<span class="line"><span>缓存 集群   → Redis Cluster / Sentinel</span></span>
<span class="line"><span>MQ 多副本   → Kafka 副本因子 ≥ 3</span></span>
<span class="line"><span>配置中心 集群 → Nacos / Etcd 多节点</span></span></code></pre></div><p><strong>任何一处单点 = 整体可用性瓶颈</strong>。审视架构图时,<strong>用红笔圈出所有&quot;只有一个&quot;的组件</strong>——那就是你的故障点。</p><hr><h2 id="三、第二件套-故障转移-failover" tabindex="-1">三、第二件套:故障转移(Failover) <a class="header-anchor" href="#三、第二件套-故障转移-failover" aria-label="Permalink to &quot;三、第二件套:故障转移(Failover)&quot;">​</a></h2><p>冗余只是「准备好了备份」,<strong>故障发生时能不能自动切走流量</strong>才是关键。</p><h3 id="_3-1-故障转移的两种模式" tabindex="-1">3.1 故障转移的两种模式 <a class="header-anchor" href="#_3-1-故障转移的两种模式" aria-label="Permalink to &quot;3.1 故障转移的两种模式&quot;">​</a></h3><p><strong>主备(Active-Standby)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>平时只有主在工作,备在等</span></span>
<span class="line"><span>主挂 → 备升主,接管流量</span></span>
<span class="line"><span>切换时间 = 检测时间 + 切换时间(几秒~几分钟)</span></span></code></pre></div><p>适合:有状态服务(DB、ZK、Redis Master),只能一个写。</p><p><strong>双活(Active-Active)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>两个都在工作,都接受流量</span></span>
<span class="line"><span>一个挂,流量自动切到另一个</span></span>
<span class="line"><span>切换时间 ≈ 0(LB 自动剔除)</span></span></code></pre></div><p>适合:无状态服务(Web、API)。</p><blockquote><p><strong>无状态服务必须双活</strong>(成本和切换时间都更优);<strong>有状态服务大多只能主备</strong>(数据一致性约束)。</p></blockquote><h3 id="_3-2-几种典型故障转移方案" tabindex="-1">3.2 几种典型故障转移方案 <a class="header-anchor" href="#_3-2-几种典型故障转移方案" aria-label="Permalink to &quot;3.2 几种典型故障转移方案&quot;">​</a></h3><table tabindex="0"><thead><tr><th>组件</th><th>方案</th></tr></thead><tbody><tr><td>域名层</td><td>DNS 多解析 + TTL 短(60s),挂了改 DNS 切流量</td></tr><tr><td>入口层</td><td>LB 双机 + VIP 漂移(keepalived)</td></tr><tr><td>应用层</td><td>LB 健康检查自动剔除挂的实例</td></tr><tr><td>MySQL</td><td>MHA / Orchestrator / Patroni 自动选主</td></tr><tr><td>Redis</td><td>Sentinel 哨兵 / Redis Cluster gossip</td></tr><tr><td>Kafka</td><td>Controller 自动重平衡分区 leader</td></tr><tr><td>ZooKeeper / etcd</td><td>Raft 自动选主</td></tr></tbody></table><h3 id="_3-3-故障转移的「脑裂」陷阱" tabindex="-1">3.3 故障转移的「脑裂」陷阱 <a class="header-anchor" href="#_3-3-故障转移的「脑裂」陷阱" aria-label="Permalink to &quot;3.3 故障转移的「脑裂」陷阱&quot;">​</a></h3><p>最危险的故障模式:<strong>网络分区导致两个节点都以为自己是主</strong>——双主同时写,数据冲突,事后无法合并。</p><p><strong>防脑裂的常用招</strong>:</p><ul><li><strong>多数派(Quorum)</strong>:写需要 majority 确认,少数派分区方拒写</li><li><strong>Fencing Token</strong>:每次选主递增编号,旧主试图写时被拒</li><li><strong>STONITH</strong>(Shoot The Other Node In The Head):新主上任前强行断电旧主</li></ul><blockquote><p>单纯的「主备 + 心跳」<strong>几乎一定会脑裂</strong>——网络抖动时两边都看不见对方。<strong>所以现代分布式系统几乎都用 Raft / Paxos</strong> 这种基于多数派的算法。</p></blockquote><h3 id="_3-4-故障转移的反向风险-误切换" tabindex="-1">3.4 故障转移的反向风险:误切换 <a class="header-anchor" href="#_3-4-故障转移的反向风险-误切换" aria-label="Permalink to &quot;3.4 故障转移的反向风险:误切换&quot;">​</a></h3><p><strong>实际事故里,1/3 是误切换造成的</strong>——主好好的,因为网络抖动被判定挂了,触发切换,反而中断服务。</p><p><strong>对策</strong>:</p><ul><li>健康检查要<strong>抗抖动</strong>(N 次失败才算挂)</li><li>切换前<strong>人工确认</strong>(关键系统)</li><li>切换有<strong>冷却期</strong>(刚切完不能立刻再切,防震荡)</li></ul><hr><h2 id="四、第三件套-健康检查-health-check" tabindex="-1">四、第三件套:健康检查(Health Check) <a class="header-anchor" href="#四、第三件套-健康检查-health-check" aria-label="Permalink to &quot;四、第三件套:健康检查(Health Check)&quot;">​</a></h2><p>故障转移的前提是<strong>能准确判断&quot;它挂了&quot;</strong>。健康检查做不好,要么真挂了你不知道,要么没挂被你切了。</p><h3 id="_4-1-健康检查的三层" tabindex="-1">4.1 健康检查的三层 <a class="header-anchor" href="#_4-1-健康检查的三层" aria-label="Permalink to &quot;4.1 健康检查的三层&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 进程级:进程还在吗?     端口能不能 telnet 通</span></span>
<span class="line"><span>2. 接口级:HTTP 200 吗?   /health 接口,K8s readinessProbe</span></span>
<span class="line"><span>3. 业务级:业务真的能跑吗?  比如查一个测试用户能不能查到</span></span></code></pre></div><p><strong>只做进程级是不够的</strong>——一个进程可能在但内部死锁,接口已经响应不了。</p><h3 id="_4-2-健康检查的间隔与判定" tabindex="-1">4.2 健康检查的间隔与判定 <a class="header-anchor" href="#_4-2-健康检查的间隔与判定" aria-label="Permalink to &quot;4.2 健康检查的间隔与判定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>推荐值</th><th>说明</th></tr></thead><tbody><tr><td>间隔</td><td>1-5 秒</td><td>越短发现越快,但开销越大</td></tr><tr><td>超时</td><td>1-3 秒</td><td>比间隔稍小</td></tr><tr><td>失败次数判定挂</td><td>3 次连续</td><td>1 次就判定容易误判,5 次太慢</td></tr><tr><td>成功次数判定活</td><td>2-3 次</td><td>防止&quot;刚好缓过来又挂&quot;的震荡</td></tr></tbody></table><h3 id="_4-3-健康检查的反模式" tabindex="-1">4.3 健康检查的反模式 <a class="header-anchor" href="#_4-3-健康检查的反模式" aria-label="Permalink to &quot;4.3 健康检查的反模式&quot;">​</a></h3><p><strong>反模式 1:健康检查接口依赖 DB</strong></p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">@app.get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/health&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> health</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">():</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    db.ping()  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ❌ DB 抖一下健康检查就失败,大量实例被剔除</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;OK&quot;</span></span></code></pre></div><p><strong>对策</strong>:<code>/health</code> 只判进程内部状态;另开 <code>/health/deep</code> 检查依赖,人工或监控用。</p><p><strong>反模式 2:健康检查太重</strong></p><p>每秒调用复杂业务逻辑作为健康检查,<strong>心跳本身把系统打挂</strong>。</p><p><strong>反模式 3:不区分 readiness / liveness</strong></p><ul><li><strong>liveness</strong>:进程是否要重启(内部死锁了)</li><li><strong>readiness</strong>:能不能接流量(还在初始化,流量不要进)</li></ul><p>K8s 把这两个分开,新手经常合用一个,<strong>结果初始化慢的服务一启动就被剔除</strong>。</p><h3 id="_4-4-主动-vs-被动健康检查" tabindex="-1">4.4 主动 vs 被动健康检查 <a class="header-anchor" href="#_4-4-主动-vs-被动健康检查" aria-label="Permalink to &quot;4.4 主动 vs 被动健康检查&quot;">​</a></h3><ul><li><strong>主动</strong>:LB / 监控定时探活——实时性高,但增加无效请求</li><li><strong>被动</strong>:观察真实请求的失败率——不增加请求,但发现慢</li></ul><p><strong>生产上两者结合</strong>:Nginx 和 Envoy 都支持 <code>passive health check</code>,真实请求 N 次失败自动剔除一段时间。</p><hr><h2 id="五、可用性-1-−-mttr-mttf-mttr" tabindex="-1">五、可用性 = 1 − MTTR / (MTTF + MTTR) <a class="header-anchor" href="#五、可用性-1-−-mttr-mttf-mttr" aria-label="Permalink to &quot;五、可用性 = 1 − MTTR / (MTTF + MTTR)&quot;">​</a></h2><p>工程视角下可用性的本质公式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MTTF = Mean Time To Failure  (平均无故障时间)</span></span>
<span class="line"><span>MTTR = Mean Time To Recovery (平均恢复时间)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>可用性 = MTTF / (MTTF + MTTR)</span></span></code></pre></div><p>提高可用性两条路:</p><ol><li><strong>延长 MTTF</strong>——更可靠的硬件、更稳定的代码、压测预防</li><li><strong>缩短 MTTR</strong>——监控更快报警、自动化恢复、预案演练</li></ol><blockquote><p><strong>现代高可用工程的重点是 MTTR,不是 MTTF</strong>——故障无法消灭,但能从「发现 30 分钟 + 处理 1 小时」缩短到「自动切换 30 秒」。<strong>「故障管理」比「故障预防」回报更高</strong>。</p></blockquote><h3 id="_5-1-缩短-mttr-的工程动作" tabindex="-1">5.1 缩短 MTTR 的工程动作 <a class="header-anchor" href="#_5-1-缩短-mttr-的工程动作" aria-label="Permalink to &quot;5.1 缩短 MTTR 的工程动作&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>监控  → 30 秒内发现异常</span></span>
<span class="line"><span>报警  → 1 分钟内通知到人(或自动触发预案)</span></span>
<span class="line"><span>诊断  → 链路追踪 + 日志聚合,5 分钟定位</span></span>
<span class="line"><span>恢复  → 自动:故障转移 / 限流 / 降级</span></span>
<span class="line"><span>       手动:重启 / 回滚 / 紧急扩容</span></span>
<span class="line"><span>复盘  → 不只是写文档,改进监控 + 演练</span></span></code></pre></div><hr><h2 id="六、混沌工程-主动制造故障" tabindex="-1">六、混沌工程:主动制造故障 <a class="header-anchor" href="#六、混沌工程-主动制造故障" aria-label="Permalink to &quot;六、混沌工程:主动制造故障&quot;">​</a></h2><p><strong>没演练过的预案 = 没有预案</strong>。Netflix 发明的混沌工程(Chaos Engineering)思想:</p><ul><li><strong>Chaos Monkey</strong>:随机杀生产环境的实例</li><li><strong>Chaos Kong</strong>:随机让一个 AZ 下线</li><li><strong>Latency Monkey</strong>:随机给请求加延迟</li><li><strong>Conformity Monkey</strong>:随机找出违反最佳实践的实例</li></ul><blockquote><p><strong>不主动制造故障,故障会用最糟糕的时机找你</strong>——双 11 当天、半夜两点、节假日。混沌工程的本质是<strong>把不可避免的故障&quot;提前到&quot;工作时间</strong>,以便修复。</p></blockquote><h3 id="_6-1-落地建议" tabindex="-1">6.1 落地建议 <a class="header-anchor" href="#_6-1-落地建议" aria-label="Permalink to &quot;6.1 落地建议&quot;">​</a></h3><p>不一定要完整搬 Netflix 那套,小公司可以从这些做起:</p><ul><li><strong>强制每月演练一次主从切换</strong>——别等到主真挂了发现切不动</li><li><strong>机房断网演练</strong>——拔一个 AZ 的网线,看流量是否自动切走</li><li><strong>依赖服务超时演练</strong>——人为给某个下游加 5s 延迟,看上游是不是被拖死</li></ul><hr><h2 id="七、sla-slo-sli-可用性的「契约语言」" tabindex="-1">七、SLA / SLO / SLI:可用性的「契约语言」 <a class="header-anchor" href="#七、sla-slo-sli-可用性的「契约语言」" aria-label="Permalink to &quot;七、SLA / SLO / SLI:可用性的「契约语言」&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>含义</th></tr></thead><tbody><tr><td><strong>SLI</strong>(Indicator)</td><td>你测量什么(请求成功率、p99 延迟)</td></tr><tr><td><strong>SLO</strong>(Objective)</td><td>你内部目标(99.95% 成功率)</td></tr><tr><td><strong>SLA</strong>(Agreement)</td><td>你对客户的承诺(99.9% 不达成赔钱)</td></tr></tbody></table><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SLI ⊆ SLO ⊆ SLA</span></span>
<span class="line"><span>内部目标永远比对外承诺严</span></span></code></pre></div><p><strong>误差预算(Error Budget)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>若 SLO = 99.9%,则一个月允许故障 43.8 分钟</span></span>
<span class="line"><span>这就是「故障预算」——超出后必须停止上新功能,先修稳定性</span></span></code></pre></div><blockquote><p>误差预算是<strong>业务和稳定性之间的契约</strong>——平时让产品团队自由迭代,预算用光了大家一起停下来还债。<strong>没有预算的稳定性管理,是吵架,不是工程</strong>。</p></blockquote><hr><h2 id="八、工程清单-让一个系统达到-99-95" tabindex="-1">八、工程清单:让一个系统达到 99.95% <a class="header-anchor" href="#八、工程清单-让一个系统达到-99-95" aria-label="Permalink to &quot;八、工程清单:让一个系统达到 99.95%&quot;">​</a></h2><p>按这个清单一项一项打钩:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>□ 应用无状态,可水平扩展</span></span>
<span class="line"><span>□ 至少跨 2 个 AZ 部署,N+2 副本</span></span>
<span class="line"><span>□ DB 主从复制,有自动主从切换(MHA / Orchestrator)</span></span>
<span class="line"><span>□ Redis 哨兵 / Cluster</span></span>
<span class="line"><span>□ MQ 副本因子 ≥ 3,acks=all</span></span>
<span class="line"><span>□ 配置中心 / 注册中心多节点</span></span>
<span class="line"><span>□ 入口层有限流和熔断</span></span>
<span class="line"><span>□ 健康检查覆盖三层(进程 / 接口 / 业务)</span></span>
<span class="line"><span>□ 监控 + 报警:CPU / 内存 / 错误率 / p99 延迟</span></span>
<span class="line"><span>□ 链路追踪 + 集中日志</span></span>
<span class="line"><span>□ 灰度发布 / 金丝雀 / 自动回滚</span></span>
<span class="line"><span>□ 关键预案文档化 + 季度演练</span></span>
<span class="line"><span>□ SLO 定义 + 误差预算管理</span></span></code></pre></div><blockquote><p>打满后不是 100% 可用,是<strong>有资格谈 99.95%</strong>——剩下的取决于运营团队的反应速度和混沌演练。</p></blockquote><hr><h2 id="九、踩坑提醒" tabindex="-1">九、踩坑提醒 <a class="header-anchor" href="#九、踩坑提醒" aria-label="Permalink to &quot;九、踩坑提醒&quot;">​</a></h2><ol><li><strong>吹「五个 9」</strong>——五个 9 = 一年挂 5 分钟,99% 的业务做不到也不需要</li><li><strong>副本只配 N+1</strong>——单点维护或挂时还能扛,但不能扛同时两个事件</li><li><strong>冗余只到机器</strong>——机架 / 机房 / 地域级冗余不做,大故障一来全瘫</li><li><strong>故障检测太敏感</strong>——网络抖一下就切主,引发震荡</li><li><strong>健康检查依赖整条链路</strong>——DB 抖一下所有 Web 实例被剔除</li><li><strong>不演练就以为切得过去</strong>——真正切的时候发现配置过期 / 权限缺失</li><li><strong>只防&quot;机器挂&quot;不防&quot;软件 bug&quot;</strong>——80% 的故障是发版引起,不是硬件</li><li><strong>SLA / SLO 写文档不执行</strong>——超预算照常发版,等于没定</li><li><strong>可用性数字只算&quot;全挂&quot;</strong>——慢请求、错误响应也是不可用,<strong>SLI 要含错误率和延迟</strong></li><li><strong>以为 K8s 自带高可用</strong>——K8s 给你工具,但应用配错(不写 PDB / 没多 AZ / 不写 readinessProbe)依然会单点</li></ol><hr><h2 id="第一层小结" tabindex="-1">第一层小结 <a class="header-anchor" href="#第一层小结" aria-label="Permalink to &quot;第一层小结&quot;">​</a></h2><p>01-05 这五篇是<strong>系统设计的&quot;心智地基&quot;</strong>:</p><ul><li>01 教你怎么从需求开始想</li><li>02 教你怎么把需求翻成数字</li><li>03 教你架构怎么一步步演进</li><li>04 教你 CAP 在工程里到底怎么用</li><li>05 教你高可用的三件基本武器</li></ul><p><strong>看完这五篇,你应该能在白板前拒绝&quot;上来就画图&quot;,而是先问需求、估容量、定一致性档位、然后逐步演进</strong>。这套思维比任何方案重要——方案永远在变,思维不变。</p><hr><p>下一篇:<code>06-负载均衡.md</code>,进入第二层&quot;抗压基础设施&quot;。负载均衡是分布式系统的&quot;流量分发中枢&quot;,<strong>讲清楚 L4(IP/端口)和 L7(HTTP)的本质差异</strong>,DNS / Anycast / Nginx / LVS 各自的位置,以及为什么没有&quot;最好的 LB&quot;,只有&quot;对应位置的 LB&quot;。</p>`,114)])])}const u=s(o,[["render",l]]);export{c as __pageData,u as default};
